// Primitive type annotations
let username: string = 'Alice';
let age: number = 30;
let isActive: boolean = true;
let data: null = null;
let maybe: undefined = undefined;

// Arrays
let names: string[] = ['Alice', 'Bob'];
let scores: number[] = [95, 87, 92];
let matrix: number[][] = [[1, 2], [3, 4]];

// Tuples (fixed-length arrays with specific types)
let coordinate: [number, number] = [40.7, -74.0];
let entry: [string, number] = ['Alice', 30];

// Union types (can be one of several types)
let id: string | number = 'abc123';
id = 42; // also valid

// Literal types (restrict to specific values)
type Direction = 'north' | 'south' | 'east' | 'west';
type HttpMethod = 'GET' | 'POST' | 'PUT' | 'DELETE';
type StatusCode = 200 | 201 | 400 | 404 | 500;

let dir: Direction = 'north'; // only these 4 values are allowed

// Function types
function add(a: number, b: number): number {
  return a + b;
}

const greet = (name: string): string => {
  return `Hello, ${name}!`;
};

// Optional and default parameters
function createUser(name: string, age?: number, role: string = 'user') {
  return { name, age, role };
}

// Interface: describes the shape of an object
interface User {
  id: number;
  name: string;
  email: string;
  bio?: string;           // Optional
  readonly createdAt: Date; // Cannot be changed after creation
}

// Extending interfaces
interface AdminUser extends User {
  permissions: string[];
  department: string;
}

// Type alias (similar to interface, but more flexible)
type ApiResponse<T> = {
  data: T;
  status: number;
  message: string;
};

// Using generics -- T is a placeholder for any type
type UserResponse = ApiResponse<User>;
type UsersResponse = ApiResponse<User[]>;

// Generic function
function getFirst<T>(items: T[]): T | undefined {
  return items[0];
}

const firstNumber = getFirst([1, 2, 3]);       // type: number | undefined
const firstString = getFirst(['a', 'b', 'c']); // type: string | undefined

// Generic with constraints
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}

const user: User = { id: 1, name: 'Alice', email: 'a@b.com', createdAt: new Date() };
const name = getProperty(user, 'name'); // type: string
